-- ----------------------------
-- Table structure for alert_records
-- ----------------------------
DROP TABLE IF EXISTS `alert_records`;
CREATE TABLE `alert_records`  (
  `alert_id` int NOT NULL COMMENT '预警ID',
  `handler_id` int NOT NULL COMMENT '处理人ID',
  `action` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '处理动作',
  `result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '处理结果',
  `id` int NOT NULL AUTO_INCREMENT,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `handler_id`(`handler_id` ASC) USING BTREE,
  INDEX `ix_alert_records_alert_id`(`alert_id` ASC) USING BTREE,
  INDEX `ix_alert_records_id`(`id` ASC) USING BTREE,
  CONSTRAINT `alert_records_ibfk_1` FOREIGN KEY (`alert_id`) REFERENCES `alerts` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `alert_records_ibfk_2` FOREIGN KEY (`handler_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

