-- ----------------------------
-- Table structure for rules
-- ----------------------------
DROP TABLE IF EXISTS `rules`;
CREATE TABLE `rules`  (
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则编码',
  `type` enum('SCORE','ATTENDANCE','GRADUATION') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则类型',
  `conditions` json NOT NULL COMMENT '规则条件(JSON格式)',
  `level` enum('WARNING','SERIOUS','URGENT') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '预警级别',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '规则描述',
  `message_template` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '预警消息模板',
  `is_active` tinyint(1) NULL DEFAULT NULL COMMENT '是否启用',
  `id` int NOT NULL AUTO_INCREMENT,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `target_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'all' COMMENT '目标类型: all-全部, grades-按年级, classes-按班级',
  `target_grades` json NULL COMMENT '目标年级列表',
  `target_classes` json NULL COMMENT '目标班级ID列表',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `ix_rules_code`(`code` ASC) USING BTREE,
  INDEX `ix_rules_id`(`id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 25 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

